        """Register a persistent listener."""
        self._listeners[event].add(callback)

    def once(self, event, callback):
        """Register a listener that fires only once."""
        # Store (callback, is_fired: bool=False)
        self._once_listeners[event].append({'cb': callback, 'fired': False})
        # We also track it in _listeners to ensure emit finds it initially, 
        # but we need a way to manage the lifecycle/removal. 
        # A simpler approach for once is just tracking them here and managing removal manually in emit.

