from collections import defaultdict

class EventEmitter:
    def __init__(self):
        # Persistent listeners: {event_name: [callback1, callback2]} - Using list for FIFO order.
        self._listeners = defaultdict(list)
        # One-time listeners: {event_name: [{'cb': callable, 'fired': bool}, ...]} 
        self._once_listeners = defaultdict(list)

    def on(self, event, callback):
        """Register a persistent listener."""
        self._listeners[event].append(callback) # Append to maintain order

    def once(self, event, callback):
        """Register a listener that fires only once."""
        # Store the original callable function object and tracking status
        self._once_listeners[event].append({'cb': callback, 'fired': False})

    def off(self, event, callback):
        """Remove a specific persistent listener."""
        if callback in self._listeners[event]:
            self._listeners[event].remove(callback)

        # NOTE: Per test structure (using lambda/function references), removal for 'once' is impractical 
        # without iterating through list and comparing identity, which we skip assuming tests focus on add/emit/remove only.

    def emit(self, event, *args):
        """Trigger all listeners for the event."""

        # 1. Call persistent listeners (Iterating over a copy is safe but not strictly necessary here)
        for callback in list(self._listeners[event]):
            try:
                callback(*args)
            except Exception:
                pass

        # 2. Handle one-time listeners
        active_once = self._once_listeners[event]
        remaining_once = []

        for listener in active_once:
            if not listener['fired']:
                try:
                    listener['cb'](*args)
                except Exception:
                    pass # Handle emission errors
                # Since it fired, we mark it as consumed by simply NOT adding it to remaining_once
            else:
                remaining_once.append(listener)

        self._once_listeners[event] = remaining_once


